      (s) => !s.deliveredDate && new Date(s.slaDate) < nowDate
    );
    if (hasDelayedShipment) signals.push("Delayed shipment");

    const hasEscalatedSupport = (doc.supportCases || []).some(
      (c) => c.status === "open" && (c.severity === "high" || c.severity === "critical")
    );
